// src/lib/validation/schemas.ts
import { z } from 'zod';

// ---------------------------------------------------------------------------
// Page content — generated by Claude from recommendationId
// ---------------------------------------------------------------------------

export const FeatureCardSchema = z.object({
  taskId:      z.string().describe('The roadmap task ID this feature maps to'),
  title:       z.string().describe('Feature name — short, specific, verb-free (e.g. "Automated invoicing")'),
  description: z.string().describe('One sentence: what this feature does for the user, in plain language'),
  benefit:     z.string().describe('One sentence: the concrete outcome the user gets from this feature'),
});

export const SurveyOptionSchema = z.object({
  id:    z.string(),
  label: z.string().describe('Short option label shown to the user'),
});

export const ValidationPageContentSchema = z.object({
  // Hero
  headline:         z.string().describe('Main headline — one punchy sentence, problem-first, no jargon'),
  subheadline:      z.string().describe('Supporting sentence expanding the headline — specific to their market'),
  // Problem + solution
  problemStatement: z.string().describe('2–3 sentences: the exact pain this solves, in the target user\'s own language'),
  solutionStatement: z.string().describe('2–3 sentences: how this product solves it — specific, not generic'),
  // Features (one per roadmap task — 3 to 6)
  features:         z.array(FeatureCardSchema).min(2).max(6),
  // CTA
  ctaHeadline:      z.string().describe('Call-to-action headline above the signup form'),
  ctaButtonLabel:   z.string().describe('Button label — 2–4 words, action-oriented (e.g. "Join the waitlist")'),
  ctaPlaceholder:   z.string().describe('Email input placeholder text'),
  // Entry survey — shown after signup
  entrySurveyQuestion: z.string().describe('One question: "What made you sign up?" or similar'),
  entrySurveyOptions:  z.array(SurveyOptionSchema).min(2).max(4),
  // Exit intent survey — shown on scroll-away
  exitSurveyQuestion:  z.string().describe('One question: "What almost stopped you?" or similar'),
  exitSurveyOptions:   z.array(SurveyOptionSchema).min(2).max(4),
  // Meta
  metaTitle:        z.string().describe('Page title for SEO/sharing — under 60 characters'),
  metaDescription:  z.string().describe('Page description for sharing cards — under 160 characters'),
});

export type FeatureCard             = z.infer<typeof FeatureCardSchema>;
export type ValidationPageContent   = z.infer<typeof ValidationPageContentSchema>;

// ---------------------------------------------------------------------------
// Distribution brief — generated at publish time
// ---------------------------------------------------------------------------

export const DistributionChannelSchema = z.object({
  channel:       z.string().describe('Specific channel name — never a category (e.g. "Accra Startup Hub WhatsApp group", not "WhatsApp groups")'),
  message:       z.string().describe('The exact message to send — written in the founder\'s voice, referencing their specific product'),
  expectedYield: z.string().describe('Honest, realistic yield estimate (e.g. "typically 5–15 clicks in an active group of 100+")'),
  audienceReason: z.string().describe('One sentence: why this channel for this specific person and market'),
});

export const DistributionBriefSchema = z.array(DistributionChannelSchema).length(3);

export type DistributionChannel = z.infer<typeof DistributionChannelSchema>;
export type DistributionBrief   = z.infer<typeof DistributionBriefSchema>;

// ---------------------------------------------------------------------------
// Snapshot analytics — PostHog data per reporting cycle
// ---------------------------------------------------------------------------

export const FeatureClickDataSchema = z.object({
  taskId:  z.string(),
  title:   z.string(),
  clicks:  z.number().int().min(0),
});

export const SurveyResponseSchema = z.object({
  question: z.string(),
  answer:   z.string(),
  takenAt:  z.string(),
});

export const TrafficSourceSchema = z.object({
  source: z.string(), // 'direct' | 'social' | 'email' | 'search' | 'other'
  count:  z.number().int().min(0),
});

export const ScrollDepthSchema = z.object({
  depth:             z.number(), // percentage milestone: 25, 50, 75, 100
  reachedPercentage: z.number(), // % of visitors who reached this depth
});

export type FeatureClickData = z.infer<typeof FeatureClickDataSchema>;
export type SurveyResponse   = z.infer<typeof SurveyResponseSchema>;

// ---------------------------------------------------------------------------
// Interpretation — Step 1 Sonnet output
// ---------------------------------------------------------------------------

export const ValidationInterpretationSchema = z.object({
  signalStrength:      z.enum(['strong', 'moderate', 'weak', 'insufficient']),
  signalReason:        z.string().describe('One sentence explaining the signal strength score with the number behind it'),
  featureRanking:      z.array(z.object({
    taskId:     z.string(),
    title:      z.string(),
    clicks:     z.number(),
    percentage: z.number(), // share of total feature clicks
    assessment: z.string(), // 'strong_interest' | 'moderate_interest' | 'low_interest' | 'no_interest'
  })),
  conversionAssessment: z.string().describe('How the CTA conversion rate compares to baseline expectations — one sentence'),
  surveyThemes:         z.array(z.string()).describe('Key themes extracted from survey responses — in the user\'s own words, not paraphrased'),
  trafficAssessment:    z.string().describe('Visitor count vs time elapsed vs distribution brief completion — one sentence'),
  nextAction:           z.string().describe('Specific instruction for what the founder should do next — never generic'),
});

export type ValidationInterpretation = z.infer<typeof ValidationInterpretationSchema>;

// ---------------------------------------------------------------------------
// Report — Step 2 Opus output (gated behind thresholds)
// ---------------------------------------------------------------------------

export const ConfirmedFeatureSchema = z.object({
  taskId:     z.string(),
  title:      z.string(),
  clicks:     z.number(),
  percentage: z.number(),
  evidence:   z.string().describe('What the data and survey responses say about this feature specifically'),
});

export const RejectedFeatureSchema = z.object({
  taskId: z.string(),
  title:  z.string(),
  clicks: z.number(),
  reason: z.string().describe('Plain-language explanation of why this feature did not resonate'),
});

export const ValidationReportSchema = z.object({
  signalStrength:    z.enum(['strong', 'moderate', 'weak']),
  confirmedFeatures: z.array(ConfirmedFeatureSchema).describe('Features the market expressed clear interest in — ranked by volume'),
  rejectedFeatures:  z.array(RejectedFeatureSchema).describe('Features with low or zero interest'),
  surveyInsights:    z.string().describe('What people said in their own words — not paraphrased into corporate language'),
  buildBrief:        z.string().describe('One committed recommendation: what to build first, what to defer, what to cut. No hedging.'),
  nextAction:        z.string().describe('The single most important thing to do in the next 48 hours based on this data'),
});

export type ConfirmedFeature   = z.infer<typeof ConfirmedFeatureSchema>;
export type RejectedFeature    = z.infer<typeof RejectedFeatureSchema>;
export type ValidationReport   = z.infer<typeof ValidationReportSchema>;
